// Extract consent submission from request body
const body = $input.item.json.body || $input.item.json;

// --- Required field validation (ICH E6 GCP mandatory elements) ---
const requiredFields = [
  'trialId', 'participantId', 'participantEmail', 'participantName',
  'consentFormVersion', 'consentDate', 'signatureData'
];
const missing = requiredFields.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`GCP Compliance Failure - Missing required consent fields: ${missing.join(', ')}`);
}

// --- Validate email format ---
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.participantEmail)) {
  throw new Error(`Invalid participant email format: ${body.participantEmail}`);
}

// --- Validate consent date is not in the future ---
const consentDate = new Date(body.consentDate);
if (isNaN(consentDate.getTime())) {
  throw new Error(`Invalid consent date format: ${body.consentDate}`);
}
if (consentDate > new Date()) {
  throw new Error('Consent date cannot be in the future');
}

// --- Parse GCP checklist flags ---
const gcpChecklist = {
  capacityConfirmed: Boolean(body.capacityConfirmed),
  rightToWithdrawExplained: Boolean(body.rightToWithdrawExplained),
  risksExplained: Boolean(body.risksExplained),
  benefitsExplained: Boolean(body.benefitsExplained),
  alternativesExplained: Boolean(body.alternativesExplained),
  confidentialityExplained: Boolean(body.confidentialityExplained),
  questionsAnswered: Boolean(body.questionsAnswered),
  voluntaryParticipation: Boolean(body.voluntaryParticipation !== false),
  witnessPresent: Boolean(body.witnessName)
};

// Calculate GCP completeness score
const checklistKeys = Object.keys(gcpChecklist);
const passedChecks = checklistKeys.filter(k => gcpChecklist[k]).length;
const gcpCompletenessScore = Math.round((passedChecks / checklistKeys.length) * 100);

// --- Generate cryptographic-style record hash (deterministic) ---
const hashInput = `${body.trialId}|${body.participantId}|${body.consentFormVersion}|${body.consentDate}|${body.signatureData?.substring(0, 32)}`;
let hashValue = 0;
for (let i = 0; i < hashInput.length; i++) {
  const char = hashInput.charCodeAt(i);
  hashValue = ((hashValue << 5) - hashValue) + char;
  hashValue = hashValue & hashValue;
}
const recordHash = `SHA-${Math.abs(hashValue).toString(16).toUpperCase().padStart(8, '0')}`;

// --- Calculate consent expiry (default: 12 months from consent date) ---
const consentExpiryMonths = body.consentExpiryMonths || 12;
const expiryDate = new Date(consentDate);
expiryDate.setMonth(expiryDate.getMonth() + consentExpiryMonths);

// --- Build normalized consent record ---
const consentRecord = {
  // Identifiers
  consentRecordId: `CONS-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  trialId: body.trialId.trim().toUpperCase(),
  participantId: body.participantId.trim(),
  irbNumber: body.irbNumber || 'IRB-NOT-PROVIDED',
  sponsorId: body.sponsorId || null,
  siteId: body.siteId || null,

  // Participant details
  participantName: body.participantName.trim(),
  participantEmail: body.participantEmail.trim().toLowerCase(),
  participantDob: body.participantDob || null,
  participantLanguage: body.participantLanguage || 'en',

  // Consent details
  consentFormVersion: body.consentFormVersion.trim(),
  consentDate: consentDate.toISOString(),
  consentExpiryDate: expiryDate.toISOString(),
  consentType: body.consentType || 'INITIAL',
  signatureData: body.signatureData,
  signatureMethod: body.signatureMethod || 'ELECTRONIC',

  // Witness
  witnessName: body.witnessName || null,
  witnessEmail: body.witnessEmail || null,
  piName: body.piName || 'PRINCIPAL_INVESTIGATOR',
  piEmail: body.piEmail || 'user@example.com',

  // GCP Checklist
  gcpChecklist,
  gcpCompletenessScore,

  // Audit metadata
  recordHash,
  submittedAt: new Date().toISOString(),
  ipAddress: body.ipAddress || 'NOT_CAPTURED',
  userAgent: body.userAgent || 'NOT_CAPTURED',
  portalVersion: body.portalVersion || '1.0',
  status: 'PENDING_REVIEW'
};

return { json: { consentRecord } };

