const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle Anthropic content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Strip any markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let complianceReview;
try {
  complianceReview = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude compliance response: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Pull consent record from upstream
const consentRecord = $('Validate and Timestamp Consent').item.json.consentRecord;

// Determine final status
const finalStatus = complianceReview.approvalRecommendation === 'APPROVE'
  ? 'APPROVED'
  : complianceReview.approvalRecommendation === 'CONDITIONAL_APPROVE'
  ? 'CONDITIONALLY_APPROVED'
  : 'REJECTED';

// Update consent record status
consentRecord.status = finalStatus;
consentRecord.complianceReviewedAt = new Date().toISOString();
consentRecord.complianceReviewedBy = 'Claude AI GCP Compliance Engine v1';

return {
  json: {
    consentRecord,
    complianceReview,
    finalStatus,
    requiresRemediaton: complianceReview.remediationRequired || false,
    requiresEscalation: complianceReview.riskLevel === 'HIGH' || complianceReview.riskLevel === 'CRITICAL',
    irbFlags: complianceReview.irbFlags || []
  }
};

const allConsents = $input.all().map(i => i.json);
const today = new Date();

// Thresholds
const EXPIRY_WARNING_DAYS = 30;
const EXPIRY_CRITICAL_DAYS = 7;

const expiringSoon = [];
const expiredAlready = [];
const expiringCritical = [];
const conditionalNotRemediated = [];

for (const consent of allConsents) {
  if (!consent.consentExpiryDate) continue;

  const expiryDate = new Date(consent.consentExpiryDate);
  const daysUntilExpiry = Math.floor((expiryDate - today) / (1000 * 60 * 60 * 24));

  if (daysUntilExpiry < 0) {
    expiredAlready.push({ ...consent, daysOverdue: Math.abs(daysUntilExpiry) });
  } else if (daysUntilExpiry <= EXPIRY_CRITICAL_DAYS) {
    expiringCritical.push({ ...consent, daysUntilExpiry });
  } else if (daysUntilExpiry <= EXPIRY_WARNING_DAYS) {
    expiringSoon.push({ ...consent, daysUntilExpiry });
  }

  if (consent.finalStatus === 'CONDITIONALLY_APPROVED' && consent.remediationRequired === 'true') {
    const reviewedAt = new Date(consent.complianceReviewedAt);
    const daysSinceReview = Math.floor((today - reviewedAt) / (1000 * 60 * 60 * 24));
    if (daysSinceReview > 7) {
      conditionalNotRemediated.push({ ...consent, daysSinceReview });
    }
  }
}

const report = {
  sweepDate: today.toISOString(),
  totalActiveConsents: allConsents.length,
  summary: {
    expired: expiredAlready.length,
    expiringCritical: expiringCritical.length,
    expiringSoon: expiringSoon.length,
    remediationOverdue: conditionalNotRemediated.length
  },
  expiredAlready,
  expiringCritical,
  expiringSoon,
  conditionalNotRemediated,
  requiresImmediateAction: expiredAlready.length + expiringCritical.length + conditionalNotRemediated.length
};

return [{ json: report }];
